<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Kanban Board</title>
    <style>
        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            margin: 20px;
            background-color: #f5f7fa;
        }

        .container {
            display: flex;
            gap: 30px;
            max-width: 1200px;
            margin: 0 auto;
        }

        /* Column headers */
        #col-todo h3 {
            font-size: 1.2rem;
            color: #333;
            text-align: center;
        }

        #col-doing h3, #col-done h3 {
            font-weight: bold;
            color: #555;
            text-align: center;
        }

        /* Card container */
        .card-container {
            flex: 1;
            background-color: white;
            border-radius: 8px;
            padding: 20px;
            box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
            display: flex;
            align-items: center;
        }

        /* Card content */
        .card {
            border-bottom: 1px solid #eee;
            padding: 15px 0;
        }

        /* Count display */
        .count {
            font-size: 1rem;
            color: #888;
            margin-top: 5px;
        }

        /* Input and button styles */
        input[type="text"] {
            width: 100%;
            padding: 8px;
            border: 1px solid #ddd;
            border-radius: 4px;
            font-size: 14px;
        }

        button {
            background-color: #007bff;
            color: white;
            border: none;
            padding: 10px 20px;
            border-radius: 4px;
            cursor: pointer;
            font-size: 16px;
        }

        button:hover {
            background-color: #0056b3;
        }

        /* Delete button */
        .delete-card {
            background-color: #dc3545;
            color: white;
            border: none;
            padding: 8px 12px;
            border-radius: 4px;
            cursor: pointer;
            font-size: 14px;
        }

        .delete-card:hover {
            background-color: #a71d2a;
        }
    </style>
</head>
<body>
    <div class="container">
        <!-- Column 1: Todo -->
        <div id="col-todo" class="card-container">
            <h3>Todo</h3>
            <div class="count">0</div>
            <input type="text" id="new-input" placeholder="New card content...">
            <button id="add-card">Add Card</button>
        </div>

        <!-- Column 2: Doing -->
        <div id="col-doing" class="card-container">
            <h3>Doing</h3>
            <div class="count">0</div>
            <input type="text" id="new-input-do" placeholder="Doing content...">
            <button id="add-card-do">Add Card</button>
        </div>

        <!-- Column 3: Done -->
        <div id="col-done" class="card-container">
            <h3>Done</h3>
            <div class="count">0</div>
            <input type="text" id="new-input-done" placeholder="Done content...">
            <button id="add-card-do">Add Card</button>
        </div>
    </div>

    <script>
        // State management
        let boardState = {
            todoCount: 0,
            doingCount: 0,
            doneCount: 0,
            cards: [
                { content: "", column: 0 },
                { content: "", column: 1 },
                { content: "", column: 2 }
            ]
        };

        // Load board state from localStorage on page load
        function loadBoardState() {
            const stored = localStorage.getItem('kanban_board_state');
            if (stored) {
                try {
                    boardState = JSON.parse(stored);
                } catch (e) {
                    console.error("Invalid JSON in localStorage", e);
                }
            }
        }

        // Save board state to localStorage
        function saveBoardState() {
            localStorage.setItem('kanban_board_state', JSON.stringify(boardState));
        }

        // Initialize board on page load
        window.addEventListener('DOMContentLoaded', () => {
            loadBoardState();

            // Add cards from input and button
            const addCard = (e) => {
                e.preventDefault();
                const content = document.getElementById('new-input').value;

                if (!content.trim()) return;

                boardState.cards[boardState.column === 0 ? 0 : 1] = { 
                    content, column: boardState.column === 0 ? 0 : 1
                };

                // Update counts in localStorage
                saveBoardState();
            };

            const addCardDo = (e) => {
                e.preventDefault();
                const content = document.getElementById('new-input-do').value;

                if (!content.trim()) return;

                boardState.cards[boardState.column === 1 ? 0 : 1] = { 
                    content, column: boardState.column === 1 ? 0 : 1
                };

                saveBoardState();
            };

            const addCardDone = (e) => {
                e.preventDefault();
                const content = document.getElementById('new-input-done').value;

                if (!content.trim()) return;

                boardState.cards[boardState.column === 2 ? 0 : 1] = { 
                    content, column: boardState.column === 2 ? 0 : 1
                };

                saveBoardState();
            };

            // Add cards to specific columns via buttons
            document.getElementById('add-card').addEventListener('click', addCard);
            document.getElementById('add-card-do').addEventListener('click', addCardDo);
            document.getElementById('add-card-do').addEventListener('click', addCardDone);
        });

        // Drag-and-drop functionality for cards
        const cardContainers = [
            document.querySelector('.card-container #col-todo'),
            document.querySelector('.card-container #col-doing'),
            document.querySelector('.card-container #col-done')
        ];

        function handleDrag(e) {
            if (e.target.classList.contains('delete-card')) return;

            // Determine which column the card belongs to
            const targetColumn = e.target.closest('.card').getAttribute('data-column');

            // Update counts in localStorage
            saveBoardState();

            // Move the card to the appropriate column
            e.target.style.opacity = '0';
            setTimeout(() => {
                e.target.style.opacity = '1';

                // Remove from current column and add to target column
                const currentContainer = document.querySelector(`.${targetColumn} .card-container`);
                if (currentContainer) {
                    currentContainer.remove();
                }

                boardState.cards[boardState.column === 0 ? 0 : 1] = { 
                    content: e.target.innerText, column: targetColumn
                };
            }, 200);
        }

        // Event listeners for drag-and-drop on columns
        cardContainers.forEach(container => {
            container.addEventListener('dragstart', handleDrag);

            // Handle drop events (when a card is dropped)
            container.addEventListener('drop', (e) => {
                e.preventDefault();

                const targetColumn = e.target.closest('.card-container').getAttribute('data-column');
                const cardElement = e.target;

                // Remove from current column
                boardState.cards[boardState.column === 0 ? 0 : 1] = { 
                    content: "", column: boardState.column === 0 ? 0 : 1
                };

                // Add to target column
                boardState.cards[boardState.column === 0 ? 0 : 1] = { 
                    content: cardElement.innerText, column: targetColumn
                };
            });
        });
    </script>
</body>
</html>
